create table demo_owners (id text primary key, display_name text not null, slug text not null unique, created_at timestamptz not null default now());
create table agents (id text primary key, canonical_name text not null, role text not null, purpose text not null, field text not null, owner_id text not null references demo_owners(id), status text not null check(status in ('ACTIVE','PARKED')), canonical_domain text, current_version integer not null default 1 check(current_version > 0), created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table agent_versions (id uuid primary key, agent_id text not null references agents(id) on delete cascade, version_number integer not null, version_type text not null, state_json jsonb not null, change_summary text not null, created_by_owner_id text not null references demo_owners(id), created_at timestamptz not null default now(), unique(agent_id,version_number));
create table agent_events (id uuid primary key, agent_id text not null references agents(id) on delete cascade, event_type text not null, actor_owner_id text not null references demo_owners(id), metadata_json jsonb not null default '{}'::jsonb, created_at timestamptz not null default now());
create table domain_bindings (id uuid primary key, agent_id text not null references agents(id) on delete cascade, domain text not null, verification_token text not null, verification_status text not null, verified_at timestamptz, created_at timestamptz not null default now());
create table transfer_tokens (id uuid primary key, agent_id text not null references agents(id) on delete cascade, from_owner_id text not null references demo_owners(id), intended_owner_id text references demo_owners(id), token_hash text not null, expires_at timestamptz not null, accepted_at timestamptz, created_at timestamptz not null default now());
create index agents_owner_idx on agents(owner_id); create index versions_agent_idx on agent_versions(agent_id,version_number); create index events_agent_idx on agent_events(agent_id,created_at); create index bindings_agent_idx on domain_bindings(agent_id); create index transfers_agent_idx on transfer_tokens(agent_id);
insert into demo_owners(id,display_name,slug) values ('owner-a','Owner A','owner-a'),('owner-b','Owner B','owner-b') on conflict (id) do nothing;
